SELECT ?actor ?character ?characterLabel WHERE {
  wd:Q936327 p:P161 ?castMember.
  ?castMember ps:P161 ?actor.
  ?castMember pq:P453 ?character.
  OPTIONAL { ?character rdfs:label ?characterLabel FILTER (LANG(?characterLabel) = "en"). }
}

SELECT ?actor ?characterLabel WHERE {
  wd:Q936327 p:P161 ?castMember.
  ?castMember ps:P161 ?actor.
  ?castMember pq:P453 ?character.
  OPTIONAL { ?character rdfs:label ?characterLabel FILTER (LANG(?characterLabel) = "en"). }
  FILTER(CONTAINS(LCASE(?characterLabel), "charline"))
}
